@pytest.mark.asyncio
async def test_validation_browser_endpoint_invalid() -> None:
    """Browser endpoint must be a valid ws:// or wss:// URL, not http://."""
    with pytest.raises(Exception) as exc_info:  # noqa: B017
        engine_config = CrawlConfig(
            browser=BrowserConfig(endpoint="http://not-websocket:3000", mode="always")
        )
        engine = create_engine(engine_config)
        url = (
            os.environ["MOCK_SERVER_URL"]
            + "/fixtures/validation_browser_endpoint_invalid"
        )
        await scrape(engine, url)
    assert (
        "endpoint" in str(exc_info.value) or "endpoint" in type(exc_info.value).__name__
    )  # noqa: S101


